import styled from "styled-components";

export const Card = styled.div`
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    text-align: start;
`;

export const Texto = styled.p`
    width: 100%;

`;

export const BoxCarrinho = styled.div`
    font-size: 0.7em;
`;
